[soc_v_uniq, idx_v] = unique(soc_v);
v_cell_uniq = v_cell(idx_v);
v_cell_interp = interp1(soc_v_uniq, v_cell_uniq, soc_unified, 'linear', 'extrap');

[soc_r_uniq, idx_r] = unique(soc_r);
r_cell_uniq = r_cell(idx_r);
r_cell_interp = interp1(soc_r_uniq, r_cell_uniq, soc_unified, 'linear', 'extrap');

% Ensure strictly 1x101 row vectors
pack_v = reshape(v_cell_interp * NumCellSer, 1, []);
pack_r = reshape(r_cell_interp * (NumCellSer / NumCellPar), 1, []);
pack_ah = BattChrgMax * NumCellPar;

Vehicle.Powertrain.Power.Battery.vNoLoad.SOC.Value = soc_unified;
Vehicle.Powertrain.Power.Battery.rTerminal.SOC.Value = soc_unified;

if isfield(Vehicle.Powertrain.Power.Battery.vNoLoad, 'T')
    numT = length(Vehicle.Powertrain.Power.Battery.vNoLoad.T.Value);
    if numT > 1
        % repmat(101x1, 1, numT) -> 101 x numT matrix (e.g. 101x7)
        Vehicle.Powertrain.Power.Battery.vNoLoad.V0.Value = repmat(pack_v', 1, numT);
        Vehicle.Powertrain.Power.Battery.rTerminal.R0.Value = repmat(pack_r', 1, numT);
    else
        Vehicle.Powertrain.Power.Battery.vNoLoad.V0.Value = pack_v';
        Vehicle.Powertrain.Power.Battery.rTerminal.R0.Value = pack_r';
    end
    Vehicle.Powertrain.Power.Battery.AhTable.Ah.Value = repmat(pack_ah, 1, numT);
else
    Vehicle.Powertrain.Power.Battery.vNoLoad.V0.Value = pack_v';
    Vehicle.Powertrain.Power.Battery.rTerminal.R0.Value = pack_r';
    Vehicle.Powertrain.Power.Battery.AhTable.Ah.Value = pack_ah;
end

Vehicle.Powertrain.Power.Battery.SOCInit.Value = BattSocInit;

